"use client";

import { useEffect, useMemo, useState } from 'react';
import { useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import { format, isAfter, subDays } from 'date-fns';
import {
  Calendar,
  FileText,
  MessageCircle,
  Plus,
  Printer,
  Search,
  User,
  Zap,
} from 'lucide-react';
import { Prescription, Medication, Patient, Doctor } from '@/types';
import { appointmentService } from '@/services/appointmentService';
import { useAuthStore } from '@/store';
import { useToast } from '@/hooks/use-toast';
import { useRecordsStore } from '@/store/recordsStore';
import { chatService } from '@/services/chatService';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Input } from '@/components/ui/input';
import { Skeleton } from '@/components/ui/skeleton';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuSeparator, DropdownMenuTrigger } from '@/components/ui/dropdown-menu';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { issuePrescription, getDoctorPrescriptions } from '../../../../features/doctor/prescriptions/actions';

type FilterMode = 'recent' | 'week' | 'all';

interface PrescriptionWithPatient extends Prescription {
  patient?: Patient;
}

const statusLabel = (rx: Prescription) => {
  const today = new Date();
  const validUntil = new Date(rx.validUntil);
  return validUntil >= today ? 'Active' : 'Expired';
};

const buildMedSummary = (meds: Medication[]) =>
  meds.slice(0, 2).map((m) => `${m.name} ${m.dosage}`).join(' + ') + (meds.length > 2 ? ` +${meds.length - 2}` : '');

export default function DoctorPrescriptionsPage() {
  const router = useRouter();
  const { user } = useAuthStore();
  const { toast } = useToast();
  const {
    prescriptions,
    setPrescriptions,
    addPrescriptionFromConsult,
  } = useRecordsStore();

  const doctor = user as Doctor | null;
  const doctorId = doctor?.id ?? '';

  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterMode, setFilterMode] = useState<FilterMode>('recent');
  const [selected, setSelected] = useState<PrescriptionWithPatient | null>(null);
  const [detailOpen, setDetailOpen] = useState(false);
  const [issueOpen, setIssueOpen] = useState(false);
  const [printOpen, setPrintOpen] = useState(false);

  const [patientId, setPatientId] = useState('');
  const [diagnosis, setDiagnosis] = useState('');
  const [instructions, setInstructions] = useState('');
  const [meds, setMeds] = useState<Medication[]>([
    { name: 'Paracetamol', dosage: '500mg', frequency: 'Every 6 hours', duration: '3 days' },
  ]);

  const [patients, setPatients] = useState<Patient[]>([]);

  useEffect(() => {
    const load = async () => {
      if (!doctorId) return;
      setLoading(true);
      const [rxRes, aptsRes] = await Promise.all([
        medicalRecordsService.getPrescriptions(doctorId),
        appointmentService.getAppointments({ doctorId }),
      ]);
      if (rxRes.success) setPrescriptions(rxRes.data);
      if (aptsRes.success) {
        const patientMap = new Map<string, Patient>();
        aptsRes.data.forEach((apt) => {
          if (apt.patient) patientMap.set(apt.patientId, apt.patient);
        });
        setPatients(Array.from(patientMap.values()));
      }
      setLoading(false);
    };
    load();
  }, [doctorId, setPrescriptions]);

  const enriched = useMemo<PrescriptionWithPatient[]>(() => {
    return prescriptions.map((rx) => ({
      ...rx,
      patient: patients.find((p) => p.id === rx.patientId),
    }));
  }, [prescriptions, patients]);

  const filtered = useMemo(() => {
    const query = searchQuery.toLowerCase();
    const weekLimit = subDays(new Date(), 7);
    return enriched.filter((rx) => {
      const matches =
        rx.patient?.name?.toLowerCase().includes(query) ||
        rx.medications.some((m) => m.name.toLowerCase().includes(query)) ||
        rx.diagnosis.toLowerCase().includes(query);

      if (!matches) return false;
      if (filterMode === 'week') return isAfter(new Date(rx.date), weekLimit);
      if (filterMode === 'recent') return isAfter(new Date(rx.date), subDays(new Date(), 30));
      return true;
    });
  }, [enriched, filterMode, searchQuery]);

  const handleIssue = async () => {
    if (!user) return;
    if (!patientId || meds.length === 0) {
      toast({ title: 'Add patient and medicines first' });
      return;
    }

    const medLines = meds
      .map((m) => `${m.name} - ${m.dosage} - ${m.frequency} - ${m.duration}`)
      .join('\n');

    const issued = await issuePrescription({
      appointmentId: '',
      patientId,
      doctorId: user.id,
      diagnosis,
      medications: medLines,
      instructions,
    });

    const newRx: Prescription = {
      ...issued,
      medications: meds,
      diagnosis: diagnosis || issued.diagnosis,
      instructions: instructions || issued.instructions,
      isDigital: true,
    };

    addPrescriptionFromConsult(newRx);
    setIssueOpen(false);
    setPatientId('');
    setDiagnosis('');
    setInstructions('');
    setMeds([{ name: 'Paracetamol', dosage: '500mg', frequency: 'Every 6 hours', duration: '3 days' }]);

    const conversationId = await chatService.createConversation(patientId, user.id);
    if (conversationId.success) {
      await chatService.sendMessage(
        conversationId.data.id,
        user.id,
        'doctor',
        'E-prescription sent. Please check My Files.',
        'prescription'
      );
    }

    toast({ title: 'Prescription issued', description: 'Sent to patient files.' });
  };

  const handleMessagePatient = async (patient: Patient | undefined) => {
    if (!user || !patient) return;
    const convRes = await chatService.createConversation(patient.id, user.id);
    if (convRes.success) {
      router.push(`/doctor/messages?conversation=${convRes.data.id}`);
    }
  };

  const handleIssueForPatient = (rx: PrescriptionWithPatient) => {
    setPatientId(rx.patientId);
    setDiagnosis(rx.diagnosis);
    setInstructions(rx.instructions);
    setMeds(rx.medications);
    setIssueOpen(true);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Prescriptions</h1>
          <p className="text-muted-foreground">Issue, review, and reprint digital prescriptions.</p>
          <div className="flex flex-wrap items-center gap-2 mt-3">
            <Badge className="bg-primary/10 text-primary border-primary/20">{prescriptions.length} issued</Badge>
            <Badge variant="secondary">{filtered.length} shown</Badge>
          </div>
        </div>
        <Button className="gap-2" onClick={() => setIssueOpen(true)}>
          <Plus className="h-4 w-4" />
          Issue New Prescription
        </Button>
      </div>

      <div className="flex flex-col lg:flex-row lg:items-center gap-4">
        <div className="relative max-w-md w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search patient, medicine, or diagnosis..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-10"
          />
        </div>
        <div className="flex flex-wrap gap-2">
          {(['recent', 'week', 'all'] as FilterMode[]).map((mode) => (
            <Button
              key={mode}
              size="sm"
              variant={filterMode === mode ? 'default' : 'outline'}
              onClick={() => setFilterMode(mode)}
            >
              {mode === 'recent' ? 'Recent' : mode === 'week' ? 'This Week' : 'All'}
            </Button>
          ))}
        </div>
      </div>

      {loading ? (
        <div className="grid md:grid-cols-2 xl:grid-cols-3 gap-4">
          {[1, 2, 3].map((i) => (
            <Skeleton key={i} className="h-44 rounded-xl" />
          ))}
        </div>
      ) : filtered.length === 0 ? (
        <EmptyState
          icon={<FileText className="h-12 w-12 text-muted-foreground/40" />}
          title="No prescriptions issued yet"
          description="Start a consult or issue a prescription to see it here."
          action={
            <div className="flex flex-wrap gap-2 justify-center">
              <Button size="sm" variant="outline" onClick={() => router.push('/doctor/patients')}>
                View Patients
              </Button>
              <Button size="sm" className="gap-2" onClick={() => router.push('/doctor/queue')}>
                <Calendar className="h-4 w-4" />
                View Queue
              </Button>
            </div>
          }
        />
      ) : (
        <div className="grid md:grid-cols-2 xl:grid-cols-3 gap-4">
          {filtered.map((rx, index) => (
            <motion.div
              key={rx.id}
              initial={{ opacity: 0, y: 16 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.04 }}
            >
              <Card className={`h-full ${statusLabel(rx) === 'Active' ? 'border-primary/20 bg-primary/5' : ''}`}>
                <CardContent className="p-4 flex flex-col gap-4">
                  <div className="flex items-start gap-3">
                    <Avatar className="h-12 w-12">
                      <AvatarImage src={rx.patient?.avatar} />
                      <AvatarFallback>{rx.patient?.name?.[0]}</AvatarFallback>
                    </Avatar>
                    <div className="flex-1 min-w-0">
                      <p className="font-semibold truncate">{rx.patient?.name ?? 'Unknown patient'}</p>
                      <p className="text-xs text-muted-foreground truncate">
                        Issued {format(new Date(rx.date), 'MMM d, yyyy')}
                      </p>
                      <p className="text-xs text-muted-foreground truncate">
                        {buildMedSummary(rx.medications)}
                      </p>
                    </div>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button variant="ghost" size="icon" className="h-8 w-8">
                          <FileText className="h-4 w-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem
                          onClick={() => {
                            setSelected(rx);
                            setDetailOpen(true);
                          }}
                        >
                          View Details
                        </DropdownMenuItem>
                        <DropdownMenuItem
                          onClick={() => {
                            setSelected(rx);
                            setPrintOpen(true);
                          }}
                        >
                          Reprint
                        </DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuItem onClick={() => handleMessagePatient(rx.patient)}>
                          Message Patient
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => handleIssueForPatient(rx)}>
                          Issue New
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </div>

                  <div className="flex flex-wrap items-center gap-2">
                    <Badge className={statusLabel(rx) === 'Active' ? 'bg-success/15 text-success border-success/30' : 'bg-muted text-muted-foreground border-border'}>
                      {statusLabel(rx)}
                    </Badge>
                    <Badge variant="secondary">{rx.medications.length} meds</Badge>
                  </div>

                  <div className="flex flex-wrap gap-2">
                    <Button
                      size="sm"
                      className="gap-1.5"
                      onClick={() => {
                        setSelected(rx);
                        setDetailOpen(true);
                      }}
                    >
                      <User className="h-3.5 w-3.5" />
                      View
                    </Button>
                    <Button
                      size="sm"
                      variant="outline"
                      className="gap-1.5"
                      onClick={() => {
                        setSelected(rx);
                        setPrintOpen(true);
                      }}
                    >
                      <Printer className="h-3.5 w-3.5" />
                      Reprint
                    </Button>
                    <Button size="sm" variant="outline" className="gap-1.5" onClick={() => handleMessagePatient(rx.patient)}>
                      <MessageCircle className="h-3.5 w-3.5" />
                      Message
                    </Button>
                  </div>
                </CardContent>
              </Card>
            </motion.div>
          ))}
        </div>
      )}

      <Dialog open={detailOpen} onOpenChange={setDetailOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Prescription Details</DialogTitle>
            <DialogDescription>Review issued medicines and instructions.</DialogDescription>
          </DialogHeader>
          {selected && (
            <div className="space-y-4">
              <div className="flex items-center gap-3">
                <Avatar className="h-12 w-12">
                  <AvatarImage src={selected.patient?.avatar} />
                  <AvatarFallback>{selected.patient?.name?.[0]}</AvatarFallback>
                </Avatar>
                <div>
                  <p className="font-semibold">{selected.patient?.name}</p>
                  <p className="text-xs text-muted-foreground">Issued {format(new Date(selected.date), 'MMM d, yyyy')}</p>
                </div>
              </div>
              <div className="rounded-lg border border-border p-3 space-y-2">
                {selected.medications.map((med, index) => (
                  <div key={`${med.name}-${index}`} className="flex flex-col sm:flex-row sm:items-center justify-between gap-2">
                    <div>
                      <p className="font-medium text-sm">{med.name}</p>
                      <p className="text-xs text-muted-foreground">{med.dosage} • {med.frequency} • {med.duration}</p>
                    </div>
                    <Badge variant="outline">Active</Badge>
                  </div>
                ))}
              </div>
              <div className="rounded-lg border border-border p-3 text-sm">
                <p className="text-muted-foreground text-xs mb-1">Instructions</p>
                <p>{selected.instructions}</p>
              </div>
              <div className="flex flex-wrap gap-2">
                <Button size="sm" className="gap-2" onClick={() => setPrintOpen(true)}>
                  <Printer className="h-4 w-4" />
                  Reprint
                </Button>
                <Button size="sm" variant="outline" onClick={() => handleMessagePatient(selected.patient)}>
                  Message Patient
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

      <Dialog open={printOpen} onOpenChange={setPrintOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Prescription Preview</DialogTitle>
          </DialogHeader>
          {selected ? (
            <div className="space-y-3 text-sm">
              <div className="rounded-lg border border-border p-3">
                <p className="font-semibold">{selected.patient?.name}</p>
                <p className="text-xs text-muted-foreground">Issued {selected.date}</p>
              </div>
              <div className="rounded-lg border border-border p-3 space-y-2">
                {selected.medications.map((med, index) => (
                  <div key={`${med.name}-${index}`} className="flex justify-between">
                    <span>{med.name}</span>
                    <span className="text-muted-foreground">{med.dosage}</span>
                  </div>
                ))}
              </div>
              <Button className="gap-2" onClick={() => toast({ title: 'Reprint queued' })}>
                <Printer className="h-4 w-4" />
                Print PDF
              </Button>
            </div>
          ) : null}
        </DialogContent>
      </Dialog>

      <Dialog open={issueOpen} onOpenChange={setIssueOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Issue New Prescription</DialogTitle>
            <DialogDescription>Fill in medicines, dosage, and instructions.</DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="grid sm:grid-cols-2 gap-3">
              <div>
                <label className="text-xs text-muted-foreground">Patient</label>
                <Select value={patientId} onValueChange={setPatientId}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select patient" />
                  </SelectTrigger>
                  <SelectContent>
                    {patients.map((p) => (
                      <SelectItem key={p.id} value={p.id}>
                        {p.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <label className="text-xs text-muted-foreground">Diagnosis</label>
                <Input value={diagnosis} onChange={(e) => setDiagnosis(e.target.value)} placeholder="e.g. Hypertension" />
              </div>
            </div>

            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <p className="text-sm font-medium">Medicines</p>
                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => setMeds((prev) => [...prev, { name: '', dosage: '', frequency: '', duration: '' }])}
                >
                  Add Row
                </Button>
              </div>
              <div className="space-y-2">
                {meds.map((med, index) => (
                  <div key={`med-${index}`} className="grid sm:grid-cols-4 gap-2">
                    <Input
                      placeholder="Medicine"
                      value={med.name}
                      onChange={(e) => {
                        const next = [...meds];
                        next[index] = { ...med, name: e.target.value };
                        setMeds(next);
                      }}
                    />
                    <Input
                      placeholder="Dosage"
                      value={med.dosage}
                      onChange={(e) => {
                        const next = [...meds];
                        next[index] = { ...med, dosage: e.target.value };
                        setMeds(next);
                      }}
                    />
                    <Input
                      placeholder="Frequency"
                      value={med.frequency}
                      onChange={(e) => {
                        const next = [...meds];
                        next[index] = { ...med, frequency: e.target.value };
                        setMeds(next);
                      }}
                    />
                    <Input
                      placeholder="Duration"
                      value={med.duration}
                      onChange={(e) => {
                        const next = [...meds];
                        next[index] = { ...med, duration: e.target.value };
                        setMeds(next);
                      }}
                    />
                  </div>
                ))}
              </div>
            </div>

            <div>
              <label className="text-xs text-muted-foreground">Instructions</label>
              <Textarea
                value={instructions}
                onChange={(e) => setInstructions(e.target.value)}
                placeholder="Take with food, avoid alcohol, follow-up in 1 week..."
              />
            </div>
          </div>
          <DialogFooter className="gap-2">
            <Button variant="outline" onClick={() => setIssueOpen(false)}>Cancel</Button>
            <Button onClick={handleIssue} className="gap-2">
              <Zap className="h-4 w-4" />
              Send to Patient
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function EmptyState({
  icon,
  title,
  description,
  action,
}: {
  icon: React.ReactNode;
  title: string;
  description: string;
  action?: React.ReactNode;
}) {
  return (
    <Card>
      <CardContent className="py-16 text-center space-y-3">
        <div className="flex justify-center">{icon}</div>
        <p className="font-semibold text-foreground">{title}</p>
        <p className="text-sm text-muted-foreground max-w-sm mx-auto">{description}</p>
        {action && <div className="pt-2">{action}</div>}
      </CardContent>
    </Card>
  );
}
